import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.DFmy_ALI.js";const h=JSON.parse('{"title":"Customer Recovery","description":"","frontmatter":{},"headers":[],"relativePath":"guide/customer-recovery.md","filePath":"guide/customer-recovery.md"}'),o={name:"guide/customer-recovery.md"};function s(d,e,i,c,l,u){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="customer-recovery" tabindex="-1">Customer Recovery <a class="header-anchor" href="#customer-recovery" aria-label="Permalink to &quot;Customer Recovery&quot;">​</a></h1><p>Customer portal recovery surfaces help support teams and customers reconstruct payment activity without exposing private account data or relying on webhook delivery.</p><h2 id="payment-history" tabindex="-1">Payment history <a class="header-anchor" href="#payment-history" aria-label="Permalink to &quot;Payment history&quot;">​</a></h2><p>Customer payment history should show one-time payments and recurring mandate charges in the same operational view when the gateway supports both. Rows should include support-safe references:</p><table tabindex="0"><thead><tr><th>Field group</th><th>Examples</th></tr></thead><tbody><tr><td>Lifecycle</td><td>status, raw status, created time, updated time, confirmed time</td></tr><tr><td>Payment</td><td>amount, currency, description, merchant name, merchant reference</td></tr><tr><td>Recovery</td><td>session id, transfer reference, settlement rail reference, refund status</td></tr><tr><td>Route context</td><td>merchant settlement account label, bank handle/name, masked IBAN, checkout channel name/environment</td></tr></tbody></table><p>CSV exports should include the same support-safe route context as JSON rows:</p><ul><li><code>merchant_account_label</code></li><li><code>merchant_account_bank_handle</code></li><li><code>merchant_account_bank_name</code></li><li><code>merchant_account_iban_masked</code></li><li><code>checkout_channel_name</code></li><li><code>checkout_channel_environment</code></li></ul><p>Exports must not include full IBANs, raw account numbers, raw customer identifiers, raw API keys, webhook signing secrets, OAuth tokens, private keys, or unmasked webhook payload bodies.</p><h2 id="support-safe-identifiers" tabindex="-1">Support-safe identifiers <a class="header-anchor" href="#support-safe-identifiers" aria-label="Permalink to &quot;Support-safe identifiers&quot;">​</a></h2><p>Customer and operator recovery screens should use references that support teams can read back to a bank, merchant, or customer without exposing private identifiers. When a customer alias, bank customer reference, phone number, national ID, or portal email is needed for triage, prefer masked display fields:</p><table tabindex="0"><thead><tr><th>Identifier</th><th>Recommended display</th></tr></thead><tbody><tr><td>Phone</td><td>last four digits only, for example <code>***4567</code></td></tr><tr><td>National ID</td><td>last four characters only, for example <code>***1234</code></td></tr><tr><td>Portal email</td><td>masked local part, for example <code>o***r@example.com</code></td></tr><tr><td>Account</td><td>masked IBAN or account alias only</td></tr><tr><td>Customer reference</td><td>bank/customer reference only when it is already support-safe</td></tr></tbody></table><p>Raw national IDs, raw phone numbers, raw portal emails, raw account numbers, passwords, reset tokens, OTPs, and authentication payload bodies should not appear in list rows, CSV exports, copied support summaries, screenshots, tickets, or logs. If an implementation needs exact values for matching, it should perform that matching server-side and return only masked values to the portal.</p><p>Customer alias route exports should include only customer-owned recovery fields such as alias, bank handle, active/inactive status, linked-account count, default masked account, default bank handle, and enrollment timestamp. They should not include full IBANs, raw account numbers, customer phone numbers, national IDs, credentials, OAuth tokens, private keys, signing secrets, or raw Identity Registry payload bodies.</p><h2 id="mandates-and-subscriptions" tabindex="-1">Mandates and subscriptions <a class="header-anchor" href="#mandates-and-subscriptions" aria-label="Permalink to &quot;Mandates and subscriptions&quot;">​</a></h2><p>Mandate recovery should include:</p><ul><li>mandate id, status, frequency, amount limit, currency, and merchant reference</li><li>consented, cancelled, created, and updated timestamps</li><li>payer bank handle and auth mode where available</li><li>support-safe settlement account and checkout channel route context</li><li>cancellation controls only where the backend supports customer cancellation</li></ul><p>Historical mandate rows should keep their original route context after a merchant changes the default settlement account or reroutes a checkout channel.</p><h2 id="open-banking-consents" tabindex="-1">Open Banking consents <a class="header-anchor" href="#open-banking-consents" aria-label="Permalink to &quot;Open Banking consents&quot;">​</a></h2><p>Open Banking consent recovery should include:</p><ul><li>consent id, TPP/client name, bank handle, scopes, and status</li><li>created, authorised, expiry, and revoked timestamps</li><li>revoke action where the consent state and backend integration allow it</li></ul><p>Consent exports should avoid raw access tokens, refresh tokens, national IDs, private account numbers, and any bank credentials.</p><h2 id="bank-customer-recovery" tabindex="-1">Bank customer recovery <a class="header-anchor" href="#bank-customer-recovery" aria-label="Permalink to &quot;Bank customer recovery&quot;">​</a></h2><p>Bank-support portals may expose a customer recovery view that resolves a bank customer reference or alias, then shows the customer&#39;s Open Banking consents and subscription mandates for that bank only.</p><p>Bank-support portals may also expose a registered customer report for the bank&#39;s OpenWave Identity population. This report should be useful for operations, enrollment support, and account-route recovery without becoming a raw identity export.</p><p>Recommended registered customer report fields:</p><table tabindex="0"><thead><tr><th>Field group</th><th>Support-safe fields</th></tr></thead><tbody><tr><td>Alias</td><td>alias username, full alias, bank handle, active/inactive status</td></tr><tr><td>Customer reference</td><td>bank customer reference when it is already support-safe</td></tr><tr><td>Contact</td><td>masked phone only</td></tr><tr><td>Enrollment</td><td>enrollment timestamp and account count</td></tr><tr><td>Default route</td><td>default account id, account label, currency, masked IBAN</td></tr></tbody></table><p>Registered customer reports should support search, active-only filtering, pagination, and capped CSV export. Search may match exact private values server-side when needed, but list rows and CSV exports should return only masked or support-safe values.</p><p>Neptune Astro exposes this implementation-specific bank portal report at <code>GET /api/v1/bank/reports/customers</code>. OpenWave Identity remains the source of truth for bank-linked aliases; its bank-scoped <code>GET /identity/accounts</code> endpoint accepts <code>activeOnly</code>, <code>page</code>, <code>limit</code>, and <code>search</code> so implementations can page at the source rather than loading every linked identity into the gateway.</p><p>Recommended bank customer recovery exports:</p><table tabindex="0"><thead><tr><th>Export</th><th>Support-safe fields</th></tr></thead><tbody><tr><td>Registered customers</td><td>alias username/full alias, bank handle, bank customer reference, masked phone, status, enrollment timestamp, account count, default account label/currency, masked default IBAN</td></tr><tr><td>Open Banking consents</td><td>consent id, client id, TPP/app name, bank handle, scopes, status, created/authorised/expires/revoked timestamps</td></tr><tr><td>Subscription mandates</td><td>mandate id, status, merchant id/name/reference, settlement account id/label/bank context, checkout channel id/name/environment, payer bank handle, amount limit, currency, frequency, created/consented/cancelled timestamps</td></tr></tbody></table><p>These exports should use the current portal filters, keep ownership bank-scoped, and apply the same bounded CSV behavior as payment and webhook reports. They should not expose raw phone numbers, national IDs, customer emails, OAuth tokens, token hashes, authorisation hashes, raw Open Banking payloads, full IBANs, raw account numbers, credentials, signing secrets, private keys, raw Identity Registry payload bodies, or raw mandate/payment payload bodies.</p><h2 id="finance-and-bnpl-history" tabindex="-1">Finance and BNPL history <a class="header-anchor" href="#finance-and-bnpl-history" aria-label="Permalink to &quot;Finance and BNPL history&quot;">​</a></h2><p>Finance recovery should connect customer-visible contracts/offers back to payment references:</p><ul><li>contract id, offer id, product type, amount, currency, and status</li><li>payment session id and repayment mandate id where present</li><li>activated, cancelled, created, and updated timestamps</li><li>repayment schedule summaries without exposing sensitive account data</li></ul><h2 id="readiness-expectations" tabindex="-1">Readiness expectations <a class="header-anchor" href="#readiness-expectations" aria-label="Permalink to &quot;Readiness expectations&quot;">​</a></h2><p>Customer recovery pages should keep loading, filter, export, and detail failures local to the affected section. A failed export or detail load should not clear unrelated history that already loaded successfully.</p><p>Recommended controls:</p><ul><li>bounded pagination for JSON lists</li><li>capped CSV exports or internal paging</li><li>copyable support summaries with only support-safe fields</li><li>clear empty states and persistent warning panels for partial failures</li><li>no dependence on merchant webhook delivery for customer-visible recovery</li></ul>',38)])])}const m=t(o,[["render",s]]);export{h as __pageData,m as default};
